use std::collections::BinaryHeap;

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let mut adj = vec![vec![]; n as usize];
    for edge in &edges {
        let u = edge[0];
        let v = edge[1];
        let s = edge[2];
        let e = edge[3];
        adj[u as usize].push( (v, s, e) );
    }

    let mut dist = vec![i64::MAX; n as usize];
    dist[0 as usize] = 0;

    let mut pq = BinaryHeap::new();
    pq.push( (0, 0) );

    while let Some( (neg_time, u) ) = pq.pop() {
        let current_time = -neg_time;
        if u == n - 1 {
            return current_time;
        }
        if current_time > dist[u as usize] {
            continue;
        }
        for (v, s, e) in &adj[u as usize] {
            let new_time = std::cmp::max(current_time, s) + 1;
            if new_time <= e {
                if new_time < dist[v as usize] {
                    dist[v as usize] = new_time;
                    pq.push( (-new_time, *v) );
                }
            }
        }
    }

    if dist[n as usize - 1] == i64::MAX {
        -1
    } else {
        dist[n as usize - 1]
    }
}
